// Lookup maps for fast access
export const STATIC_COURSE_BY_SLUG: Record<string, StaticCourse> = Object.fromEntries(STATIC_COURSES.map(c => [c.slug, c]));

export const STATIC_MODULES_BY_COURSE_ID: Record<string, StaticModule[]> = {};
STATIC_MODULES.forEach(m => { (STATIC_MODULES_BY_COURSE_ID[m.courseId] ??= []).push(m); });

export const STATIC_LESSONS_BY_MODULE_ID: Record<string, StaticLesson[]> = {};
STATIC_LESSONS.forEach(l => { (STATIC_LESSONS_BY_MODULE_ID[l.moduleId] ??= []).push(l); });

export const STATIC_LESSON_BY_ID: Record<string, StaticLesson> = Object.fromEntries(STATIC_LESSONS.map(l => [l.id, l]));

// Helper: find course and module for a given lesson ID
export function findCourseForLesson(lessonId: string): { course: StaticCourse; module: StaticModule; lesson: StaticLesson } | null {
  const lesson = STATIC_LESSON_BY_ID[lessonId];
  if (!lesson) return null;
  const module = STATIC_MODULES.find(m => m.id === lesson.moduleId);
  if (!module) return null;
  const course = STATIC_COURSES.find(c => c.id === module.courseId);
  if (!course) return null;
  return { course, module, lesson };
}